// Minimal YAML parser for workflow structure tests.
// Uses a simple JS-based approach: read the file and parse with a basic
// state machine that handles the subset of YAML used in GitHub Actions workflows.

import { execSync } from "child_process";

/**
 * Parse YAML by converting to JSON via Python (available in all environments).
 * This avoids the need for a YAML library dependency.
 */
function parse(yamlStr: string): any {
  // Use python3 to convert YAML to JSON
  const escaped = yamlStr.replace(/'/g, "'\\''");
  const result = execSync(
    `python3 -c "import sys, json, yaml; print(json.dumps(yaml.safe_load(sys.stdin.read())))"`,
    {
      input: yamlStr,
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"],
    }
  );
  return JSON.parse(result.trim());
}

export default { parse };

