// Minimal YAML parser for workflow structure tests.
// Uses Python's yaml module to parse, preserving string keys like 'on'.

import { execSync } from "child_process";

/**
 * Parse YAML by converting to JSON via Python.
 * Uses a custom loader that keeps 'on'/'off' as strings (not booleans).
 */
function parse(yamlStr: string): any {
  // Python script that overrides the boolean resolver to keep 'on'/'off' etc as strings
  const pyScript = `
import sys, json, yaml

class StringKeyLoader(yaml.SafeLoader):
    pass

# Remove the implicit boolean resolver so 'on', 'off', 'yes', 'no' stay as strings
StringKeyLoader.yaml_implicit_resolvers.pop('o', None)
StringKeyLoader.yaml_implicit_resolvers.pop('O', None)
StringKeyLoader.yaml_implicit_resolvers.pop('y', None)
StringKeyLoader.yaml_implicit_resolvers.pop('Y', None)
StringKeyLoader.yaml_implicit_resolvers.pop('n', None)
StringKeyLoader.yaml_implicit_resolvers.pop('N', None)

data = yaml.load(sys.stdin.read(), Loader=StringKeyLoader)
print(json.dumps(data))
`;
  const result = execSync(`python3 -c ${JSON.stringify(pyScript)}`, {
    input: yamlStr,
    encoding: "utf-8",
    stdio: ["pipe", "pipe", "pipe"],
  });
  return JSON.parse(result.trim());
}

export default { parse };

